// Canonical key for a bridge between two islands (grid coords)
export function bridgeKey(island1, island2) {
  const x1 = island1.x, y1 = island1.y;
  const x2 = island2.x, y2 = island2.y;
  if (x1 < x2 || (x1 === x2 && y1 < y2)) {
    return `${x1},${y1},${x2},${y2}`;
  }
  return `${x2},${y2},${x1},${y1}`;
}

// Check if two islands are adjacent (same row or column, no island in between)
export function areAdjacent(islands, from, to) {
  if (from.id === to.id) return false;
  if (from.x !== to.x && from.y !== to.y) return false;

  // Check no island in between
  if (from.x === to.x) {
    const minY = Math.min(from.y, to.y);
    const maxY = Math.max(from.y, to.y);
    for (const island of islands) {
      if (island.id === from.id || island.id === to.id) continue;
      if (island.x === from.x && island.y > minY && island.y < maxY) return false;
    }
  } else {
    const minX = Math.min(from.x, to.x);
    const maxX = Math.max(from.x, to.x);
    for (const island of islands) {
      if (island.id === from.id || island.id === to.id) continue;
      if (island.y === from.y && island.x > minX && island.x < maxX) return false;
    }
  }
  return true;
}

// Check if adding a bridge between from and to would cross any existing bridge
export function wouldCross(islands, bridges, from, to) {
  // The new bridge segment
  const isHorizontal = from.y === to.y;

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [bx1, by1, bx2, by2] = parts;
    const bridgeIsHorizontal = by1 === by2;

    // Parallel bridges can't cross
    if (isHorizontal === bridgeIsHorizontal) continue;

    // Perpendicular: check intersection
    if (isHorizontal) {
      // new bridge is horizontal, existing is vertical
      const newMinX = Math.min(from.x, to.x);
      const newMaxX = Math.max(from.x, to.x);
      const newY = from.y;
      const existX = bx1; // vertical bridge has same x
      const existMinY = Math.min(by1, by2);
      const existMaxY = Math.max(by1, by2);

      if (existX > newMinX && existX < newMaxX && newY > existMinY && newY < existMaxY) {
        return true;
      }
    } else {
      // new bridge is vertical, existing is horizontal
      const newMinY = Math.min(from.y, to.y);
      const newMaxY = Math.max(from.y, to.y);
      const newX = from.x;
      const existY = by1; // horizontal bridge has same y
      const existMinX = Math.min(bx1, bx2);
      const existMaxX = Math.max(bx1, bx2);

      if (newX > existMinX && newX < existMaxX && existY > newMinY && existY < newMaxY) {
        return true;
      }
    }
  }
  return false;
}

// Compute current bridge counts per island
export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const island of islands) {
    counts.set(island.id, 0);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [x1, y1, x2, y2] = parts;

    // Find the islands at these coordinates
    const island1 = islands.find(i => i.x === x1 && i.y === y1);
    const island2 = islands.find(i => i.x === x2 && i.y === y2);

    if (island1) counts.set(island1.id, (counts.get(island1.id) || 0) + count);
    if (island2) counts.set(island2.id, (counts.get(island2.id) || 0) + count);
  }

  return counts;
}

// Check if adding delta bridges would exceed either island's value
export function wouldExceedValue(islands, bridges, from, to, delta) {
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) || 0;
  const toCount = counts.get(to.id) || 0;

  if (fromCount + delta > from.value) return true;
  if (toCount + delta > to.value) return true;
  return false;
}

// Main validation: can we add delta bridges between from and to?
export function canAddBridge(islands, bridges, from, to, delta) {
  // Check adjacency
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  // Check max 2 bridges
  const key = bridgeKey(from, to);
  const current = bridges.get(key) || 0;
  if (current + delta > 2) {
    return { valid: false, error: "Max 2 bridges per pair" };
  }

  // Check island values
  if (wouldExceedValue(islands, bridges, from, to, delta)) {
    return { valid: false, error: "Island would exceed its number" };
  }

  // Check crossing (only if adding new bridge where none existed, or going from 1 to 2)
  if (current === 0 && wouldCross(islands, bridges, from, to)) {
    return { valid: false, error: "Bridges would cross" };
  }

  return { valid: true, error: null };
}

// Check connectivity: all islands reachable from each other via bridges
export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  // Build adjacency from bridges
  const adj = new Map();
  for (const island of islands) {
    adj.set(island.id, []);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [x1, y1, x2, y2] = parts;
    const island1 = islands.find(i => i.x === x1 && i.y === y1);
    const island2 = islands.find(i => i.x === x2 && i.y === y2);
    if (island1 && island2) {
      adj.get(island1.id).push(island2.id);
      adj.get(island2.id).push(island1.id);
    }
  }

  // BFS from first island
  const visited = new Set();
  const queue = [islands[0].id];
  visited.add(islands[0].id);

  while (queue.length > 0) {
    const current = queue.shift();
    for (const neighbor of adj.get(current)) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }

  return visited.size === islands.length;
}

// Check victory condition
export function isVictory(islands, bridges) {
  // Check all counts match values
  const counts = computeCurrentCounts(islands, bridges);
  for (const island of islands) {
    if ((counts.get(island.id) || 0) !== island.value) return false;
  }

  // Check connectivity
  if (!checkConnectivity(islands, bridges)) return false;

  // Check no crossings among existing bridges
  const bridgeList = [];
  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    bridgeList.push(parts);
  }

  for (let i = 0; i < bridgeList.length; i++) {
