  const renderBridges = () => {
    const lines = [];
    for (const [key, count] of bridges) {
      if (count === 0) continue;
      const parts = key.split(',').map(Number);
      const [x1, y1, x2, y2] = parts;
      const px1 = x1 * GRID;
      const py1 = y1 * GRID;
      const px2 = x2 * GRID;
      const py2 = y2 * GRID;

      if (count === 1) {
        lines.push(
          <line
            key={key}
            x1={px1}
            y1={py1}
            x2={px2}
            y2={py2}
            stroke="#0f0"
            strokeWidth="2"
            onClick={(e) => handleBridgeClick(key, e)}
            onContextMenu={(e) => handleBridgeRightClick(key, e)}
            style={{ cursor: 'pointer' }}
          />
        );
      } else {
